/*ReportWrite020.selectReport020OfficeSiList*/ SELECT T.DGRCOMPO_ID AS DGRCOMPO_ID , T.UP_DGRCOMPO_ID AS UP_DGRCOMPO_ID , CAST(T.DGR_LEVEL AS NUMERIC(5, 0)) AS DGR_LEVEL , CAST(T.OFFICE_CNT AS NUMERIC(5, 0)) AS OFFICE_CNT , TRIM(CASE WHEN T.DGR_LEVEL = 0 THEN '합 계' ELSE NVL(T.OFFICE_NM, '') END) AS DGRCOMPO_NM , T.OFFICE_CD AS OFFICE_CD , CAST((T.TOT_FRSC_AMT0/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS TOT_FRSC_AMT0 , CAST((T.PRE_INV_FRSC_AMT0/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_INV_FRSC_AMT0 , CAST((T.FRSC_AMT0/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS FRSC_AMT0 , CAST((T.DMN_FRSC_AMT0/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS DMN_FRSC_AMT0 , CAST((T.PRE_FRSC_AMT0/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_FRSC_AMT0 , CAST((T.PRE_DEF_FRSC_AMT0/DECODE(#amtUnit#, NULL, 1, '', 1, '0', 1, #amtUnit#)) AS NUMERIC(19,0)) AS PRE_DEF_FRSC_AMT0 FROM (SELECT A.DGRCOMPO_ID AS DGRCOMPO_ID , A.UP_DGRCOMPO_ID AS UP_DGRCOMPO_ID , A.DGR_LEVEL AS DGR_LEVEL , A.OFFICE_CNT AS OFFICE_CNT , A.OFFICE_CD AS OFFICE_CD , A.TOT_FRSC_AMT1 + A.TOT_FRSC_AMT4 + A.TOT_FRSC_AMT5 AS TOT_FRSC_AMT0 , A.PRE_INV_FRSC_AMT1 + A.PRE_INV_FRSC_AMT4 + A.PRE_INV_FRSC_AMT5 AS PRE_INV_FRSC_AMT0 , A.FRSC_AMT1 + A.FRSC_AMT4 + A.FRSC_AMT5 AS FRSC_AMT0 , A.DMN_FRSC_AMT1 + A.DMN_FRSC_AMT4 + A.DMN_FRSC_AMT5 AS DMN_FRSC_AMT0 , A.PRE_FRSC_AMT1 + A.PRE_FRSC_AMT4 + A.PRE_FRSC_AMT5 AS PRE_FRSC_AMT0 , A.PRE_DEF_FRSC_AMT1 + A.PRE_DEF_FRSC_AMT4 + A.PRE_DEF_FRSC_AMT5 AS PRE_DEF_FRSC_AMT0 , NVL((SELECT NVL(Z.OFFICE_RANK020, Z.OFFICE_RANK) FROM TB_DGROFFICE020 Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.OFFICE_CD = A.OFFICE_CD AND ROWNUM = 1), 0) AS OFFICE_RANK , NVL((SELECT Z.OFFICE_NM FROM TB_DGRDEPT Z WHERE Z.FIS_YEAR = A.FIS_YEAR AND Z.BGT_DGR = A.BGT_DGR AND Z.OFFICE_CD = A.OFFICE_CD AND ROWNUM = 1), '') AS OFFICE_NM FROM (SELECT T.* FROM (SELECT DECODE(H.CT, 1, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || '0000' , 2, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || A.OFFICE_CD) AS DGRCOMPO_ID , DECODE(H.CT, 1, A.FIS_YEAR || '_' || '000' || '_' || '0000' , 2, A.FIS_YEAR || '_' || TO_CHAR(A.BGT_DGR, '000') || '_' || '0000') AS UP_DGRCOMPO_ID , A.FIS_YEAR AS FIS_YEAR , A.BGT_DGR AS BGT_DGR , DECODE(H.CT, 1, 0, 2, 1) AS DGR_LEVEL , SUM(CASE WHEN A.COMPO_LEVEL = '1' AND #mayorReportYn# = 'Y' AND A.MAYOR_REPORT_YN = 'Y' THEN 1 WHEN A.COMPO_LEVEL = '1' AND #mayorReportYn# != 'Y' THEN 1 ELSE 0 END ) AS OFFICE_CNT , DECODE(H.CT, 1, '0000', 2, A.OFFICE_CD) AS OFFICE_CD , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_FRSC_AMT1, 0), A.TOT_FRSC_AMT1)) AS TOT_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_FRSC_AMT2, 0), A.TOT_FRSC_AMT2)) AS TOT_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_FRSC_AMT3, 0), A.TOT_FRSC_AMT3)) AS TOT_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_FRSC_AMT4, 0), A.TOT_FRSC_AMT4)) AS TOT_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_FRSC_AMT5, 0), A.TOT_FRSC_AMT5)) AS TOT_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_FRSC_AMT6, 0), A.TOT_FRSC_AMT6)) AS TOT_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_CHAR_AMT1, 0), A.TOT_CHAR_AMT1)) AS TOT_CHAR_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_CHAR_AMT2, 0), A.TOT_CHAR_AMT2)) AS TOT_CHAR_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.TOT_CHAR_AMT3, 0), A.TOT_CHAR_AMT3)) AS TOT_CHAR_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_FRSC_AMT1, 0), A.PRE_INV_FRSC_AMT1)) AS PRE_INV_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_FRSC_AMT2, 0), A.PRE_INV_FRSC_AMT2)) AS PRE_INV_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_FRSC_AMT3, 0), A.PRE_INV_FRSC_AMT3)) AS PRE_INV_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_FRSC_AMT4, 0), A.PRE_INV_FRSC_AMT4)) AS PRE_INV_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_FRSC_AMT5, 0), A.PRE_INV_FRSC_AMT5)) AS PRE_INV_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_FRSC_AMT6, 0), A.PRE_INV_FRSC_AMT6)) AS PRE_INV_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_CHAR_AMT1, 0), A.PRE_INV_CHAR_AMT1)) AS PRE_INV_CHAR_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_CHAR_AMT2, 0), A.PRE_INV_CHAR_AMT2)) AS PRE_INV_CHAR_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_INV_CHAR_AMT3, 0), A.PRE_INV_CHAR_AMT3)) AS PRE_INV_CHAR_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT1, 0), A.FRSC_AMT1)) AS FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT2, 0), A.FRSC_AMT2)) AS FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT3, 0), A.FRSC_AMT3)) AS FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT4, 0), A.FRSC_AMT4)) AS FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT5, 0), A.FRSC_AMT5)) AS FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.FRSC_AMT6, 0), A.FRSC_AMT6)) AS FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.CHAR_AMT1, 0), A.CHAR_AMT1)) AS CHAR_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.CHAR_AMT2, 0), A.CHAR_AMT2)) AS CHAR_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.CHAR_AMT3, 0), A.CHAR_AMT3)) AS CHAR_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT1, 0), A.DMN_FRSC_AMT1)) AS DMN_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT2, 0), A.DMN_FRSC_AMT2)) AS DMN_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT3, 0), A.DMN_FRSC_AMT3)) AS DMN_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT4, 0), A.DMN_FRSC_AMT4)) AS DMN_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT5, 0), A.DMN_FRSC_AMT5)) AS DMN_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_FRSC_AMT6, 0), A.DMN_FRSC_AMT6)) AS DMN_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_CHAR_AMT1, 0), A.DMN_CHAR_AMT1)) AS DMN_CHAR_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_CHAR_AMT2, 0), A.DMN_CHAR_AMT2)) AS DMN_CHAR_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.DMN_CHAR_AMT3, 0), A.DMN_CHAR_AMT3)) AS DMN_CHAR_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT1, 0), A.PRE_FRSC_AMT1)) AS PRE_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT2, 0), A.PRE_FRSC_AMT2)) AS PRE_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT3, 0), A.PRE_FRSC_AMT3)) AS PRE_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT4, 0), A.PRE_FRSC_AMT4)) AS PRE_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT5, 0), A.PRE_FRSC_AMT5)) AS PRE_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_FRSC_AMT6, 0), A.PRE_FRSC_AMT6)) AS PRE_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_CHAR_AMT1, 0), A.PRE_CHAR_AMT1)) AS PRE_CHAR_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_CHAR_AMT2, 0), A.PRE_CHAR_AMT2)) AS PRE_CHAR_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_CHAR_AMT3, 0), A.PRE_CHAR_AMT3)) AS PRE_CHAR_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT1, 0), A.PRE_DEF_FRSC_AMT1)) AS PRE_DEF_FRSC_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT2, 0), A.PRE_DEF_FRSC_AMT2)) AS PRE_DEF_FRSC_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT3, 0), A.PRE_DEF_FRSC_AMT3)) AS PRE_DEF_FRSC_AMT3 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT4, 0), A.PRE_DEF_FRSC_AMT4)) AS PRE_DEF_FRSC_AMT4 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT5, 0), A.PRE_DEF_FRSC_AMT5)) AS PRE_DEF_FRSC_AMT5 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_FRSC_AMT6, 0), A.PRE_DEF_FRSC_AMT6)) AS PRE_DEF_FRSC_AMT6 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_CHAR_AMT1, 0), A.PRE_DEF_CHAR_AMT1)) AS PRE_DEF_CHAR_AMT1 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_CHAR_AMT2, 0), A.PRE_DEF_CHAR_AMT2)) AS PRE_DEF_CHAR_AMT2 , SUM(DECODE(H.CT, 1, DECODE(A.COMPO_LEVEL, '1', A.PRE_DEF_CHAR_AMT3, 0), A.PRE_DEF_CHAR_AMT3)) AS PRE_DEF_CHAR_AMT3 FROM (SELECT A.FIS_YEAR , A.BGT_DGR , A.TE_BGT_COMPO_ID , A.UP_TE_BGT_COMPO_ID , A.COMPO_LEVEL , A.DEPT_CD , A.DBIZ_CD , A.TE_MNG_MOK_CD , A.TE_BGT_COMPO_SEQ , A.COMP_GROUND , A.SORT_SEQ , B.OFFICE_CD , E.REPORT_CD , E.REPORT_DETL_CD , E.REFLECT_FG , E.DEMAND_CONT , E.EXAM_CONT , E.SRCH_VAL , E.REPORT_SORT_SEQ , E.MAYOR_REPORT_YN , E.INVEST_PLAN , E.TOT_FRSC_AMT1 , E.TOT_FRSC_AMT2 , E.TOT_FRSC_AMT3 , E.TOT_FRSC_AMT4 , E.TOT_FRSC_AMT5 , E.TOT_FRSC_AMT6 , E.TOT_CHAR_AMT1 , E.TOT_CHAR_AMT2 , E.TOT_CHAR_AMT3 , E.PRE_INV_FRSC_AMT1 , E.PRE_INV_FRSC_AMT2 , E.PRE_INV_FRSC_AMT3 , E.PRE_INV_FRSC_AMT4 , E.PRE_INV_FRSC_AMT5 , E.PRE_INV_FRSC_AMT6 , E.PRE_INV_CHAR_AMT1 , E.PRE_INV_CHAR_AMT2 , E.PRE_INV_CHAR_AMT3 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '160', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT1 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '110', BB.ADJ_DEF_FRSC_AMT, '120', BB.ADJ_DEF_FRSC_AMT, '130', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT2 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '140', BB.ADJ_DEF_FRSC_AMT, '150', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT3 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '180', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT4 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '190', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT5 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '170', BB.ADJ_DEF_FRSC_AMT, '200', BB.ADJ_DEF_FRSC_AMT, '210', BB.ADJ_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS FRSC_AMT6 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '010', BB.ADJ_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS CHAR_AMT1 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '020', BB.ADJ_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS CHAR_AMT2 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '090', BB.ADJ_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS CHAR_AMT3 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '160', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT1 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '110', BB.DMN_DEF_FRSC_AMT, '120', BB.DMN_DEF_FRSC_AMT, '130', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT2 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '140', BB.DMN_DEF_FRSC_AMT, '150', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT3 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '180', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT4 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '190', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT5 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '170', BB.DMN_DEF_FRSC_AMT, '200', BB.DMN_DEF_FRSC_AMT, '210', BB.DMN_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS DMN_FRSC_AMT6 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '010', BB.DMN_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS 