YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_FRSC_AMT3 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '180', BB.PRE_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_FRSC_AMT4 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '190', BB.PRE_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_FRSC_AMT5 , (SELECT NVL(SUM(DECODE(CC.STAND_FRSC_CD, '170', BB.PRE_DEF_FRSC_AMT, '200', BB.PRE_DEF_FRSC_AMT, '210', BB.PRE_DEF_FRSC_AMT, 0)), 0) FROM TB_DGRCOMPOFRSC BB, TB_YEARFRSC CC WHERE 1 = 1 AND CC.FIS_YEAR = BB.FIS_YEAR AND CC.FRSC_FG_CD = BB.FRSC_FG_CD AND BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_FRSC_AMT6 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '010', BB.PRE_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_CHAR_AMT1 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '020', BB.PRE_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_CHAR_AMT2 , (SELECT NVL(SUM(DECODE(BB.CHAR_FG_CD, '090', BB.PRE_DEF_CHAR_AMT, 0)), 0) FROM TB_DGRCOMPOCHAR BB WHERE BB.FIS_YEAR = A.FIS_YEAR AND BB.BGT_DGR = A.BGT_DGR AND BB.TE_BGT_COMPO_ID = A.TE_BGT_COMPO_ID) AS PRE_DEF_CHAR_AMT3 FROM TB_DGRCOMPO A , TB_DGRDEPT B , TB_DGRBIZ C , TB_REPORT020 E WHERE 1 = 1
AND EXISTS (SELECT 1 FROM TB_USERDEPT Z WHERE Z.USER_ID = #userId# AND Z.DEPT_CD = B.DEPT_CD AND Z.USE_YN = 'Y' AND ROWNUM = 1 )
